import { Marker, Popup } from "react-leaflet";
import L from "leaflet";

export default function PlaneMarker({ position, flightData }) {
  if (!position || isNaN(position[0]) || isNaN(position[1])) return null;
  if (!flightData) return null;

  const rotation = flightData.heading || 0;

  const icon = L.divIcon({
    html: `<div style="
      width: 40px;
      height: 40px;
      display: flex;
      align-items: center;
      justify-content: center;
      background: rgba(255, 42, 42, 0.9);
      border: 2px solid #ff0000;
      border-radius: 50%;
      box-shadow: 0 0 15px rgba(255, 42, 42, 0.8);
      transform: rotate(${rotation}deg);
      transition: transform 0.5s linear;
    ">
      <span style="font-size: 20px;">✈️</span>
    </div>`,
    className: "plane-marker",
    iconSize: [40, 40],
    iconAnchor: [20, 20],
    popupAnchor: [0, -20],
  });

  return (
    <Marker position={position} icon={icon}>
      <Popup>
        <div style="color: black; font-weight: bold;">
          ✈️ {flightData.callsign}<br />
          Alt: {Math.round(flightData.altitude)} m<br />
          Speed: {Math.round(flightData.velocity)} km/h
        </div>
      </Popup>
    </Marker>
  );
}
